import{_ as e,o,c as t,a0 as n}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"Nine Sols","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/knowledge/games/Nine-Sols.md","filePath":"outta-space/knowledge/games/Nine-Sols.md"}'),r={name:"outta-space/knowledge/games/Nine-Sols.md"};function s(l,a,p,i,d,h){return o(),t("div",null,[...a[0]||(a[0]=[n('<h1 id="nine-sols" tabindex="-1">Nine Sols <a class="header-anchor" href="#nine-sols" aria-label="Permalink to &quot;Nine Sols&quot;">​</a></h1><h2 id="_1-핵심-플레이-경험" tabindex="-1">1. 핵심 플레이 경험 <a class="header-anchor" href="#_1-핵심-플레이-경험" aria-label="Permalink to &quot;1. 핵심 플레이 경험&quot;">​</a></h2><p>『Nine Sols』는 갓겜이다.</p><p>스토리, 탐험, 전투가 모두 훌륭하게 맞물린 메트로배니아다. 초반에는 영어로 진행해야 해서 진입 장벽이 있었고, 마지막에 가서는 대화를 거의 스킵할 정도로 양이 많았지만, 전체적인 이야기는 충분히 파악 가능했다.</p><p>특히 “예의 과학은 찬미와 하아의 도가 사상이 모두 틀린 것이 아니었다”는 식의 연출이 인상적이었다. 아홉 태양들이 각자의 방식으로 노력했지만 완전한 악인은 아니었다는 점도 좋았다. 다만 역공은 확실히 미친 놈이 맞다.</p><h2 id="_2-조작감과-시스템" tabindex="-1">2. 조작감과 시스템 <a class="header-anchor" href="#_2-조작감과-시스템" aria-label="Permalink to &quot;2. 조작감과 시스템&quot;">​</a></h2><p>탐험 면에서는 메트로배니아로서 평가해야 할 요소가 잘 갖춰져 있다.</p><p>탐험 난이도는 매우 쉽다. “뭐 있나?” 싶은 곳에는 대부분 무언가가 있고, 지나친 부분도 지도가 친절하게 표시해준다. 지도를 계속 들여다보면 올컬렉이 가능할 정도다. 지도 칩 기능도 난이도를 낮춰주는 좋은 장치였다.</p><p>플랫폼 난이도는 낮은 편이다. 초반에는 공중 대시와 패링에 익숙하지 않아 조금 고통스럽지만, 나중에는 숭숭 날아다니게 된다. 최후반 지역 일부에 난이도 있는 구간이 있지만, 할나 백색 궁전과 비교하면 쉬운 편이다.</p><h2 id="_3-전투와-보스전" tabindex="-1">3. 전투와 보스전 <a class="header-anchor" href="#_3-전투와-보스전" aria-label="Permalink to &quot;3. 전투와 보스전&quot;">​</a></h2><p>전투가 이 게임의 핵심이다.</p><p>모든 전투는 패링을 중심으로 해결된다. 패링 종류는 일반 패링, 초록 패링, 홀드 후 나가는 빨강 패링 세 가지가 있다. 처음에는 잡몹 상대로도 죽을 만큼 어렵지만, 익숙해지면 이만큼 재미있는 시스템이 없다.</p><p>부적부터 전투가 본격적으로 재미있어진다. 맵 연출과 보스전의 연결도 훌륭하고, 보스전은 하나의 전투라기보다 짜임새 있는 패턴을 읽고 반응하는 과정에 가깝다.</p><p>특히 역공 보스전은 매우 좋았다. 처음에는 한 시간 정도 걸려 깼지만, 깨고 나면 패턴이 정교하게 짜였다는 느낌이 강하게 남는다. 패링할 때마다 느껴지는 쾌감이 크고, 불합리한 패턴이 거의 없었다.</p><h2 id="_4-그래픽-사운드-연출" tabindex="-1">4. 그래픽, 사운드, 연출 <a class="header-anchor" href="#_4-그래픽-사운드-연출" aria-label="Permalink to &quot;4. 그래픽, 사운드, 연출&quot;">​</a></h2><p>표현과 깊이가 모두 훌륭하다.</p><p>과학, 신화, 도가 사상, 사이버펑크적인 분위기가 잘 결합되어 있다. 맵 기믹도 연출과 정확히 맞아떨어져 몰입감을 높인다.</p><p>패링 중심 전투의 타격감도 좋고, 보스전 연출은 특히 강하다. 단순히 어려운 보스가 아니라, 패턴을 이해하고 몸에 익히는 과정 자체가 재미로 이어진다.</p><h2 id="_5-몰입도와-재플레이-가치" tabindex="-1">5. 몰입도와 재플레이 가치 <a class="header-anchor" href="#_5-몰입도와-재플레이-가치" aria-label="Permalink to &quot;5. 몰입도와 재플레이 가치&quot;">​</a></h2><p>진엔딩까지 약 20시간 정도 걸린 것 같다. 할나보다 재미있었고, 정가를 주고도 할 만한 게임이다.</p><p>아쉬운 점은 스위치 버전의 해상도와 조작 환경이다. 하단 공격이 불편하다는 평 때문에 스팀판으로 플레이했는데, 큰 문제는 없었다. 다만 스위치2나 해상도가 더 좋은 버전으로 한 번 더 깨고 싶다.</p><p>한 줄 평: 패링 전투, 맵 설계, 보스전, 서사가 모두 강한 메트로배니아 갓겜.</p>',22)])])}const u=e(r,[["render",s]]);export{c as __pageData,u as default};
